// Fetch all transactions in the last N minutes (paged), then group by
// transactionType (the operation/method) with success vs error counts.

const input = $input.first().json;

let session;
try { session = typeof input.sessionJson === 'string' ? JSON.parse(input.sessionJson) : input.sessionJson; }
catch (e) { throw new Error('sessionJson is not valid JSON.'); }
if (!session.cookies || !session.token) throw new Error('session.json missing cookies or token. Re-run login.');

const cookie = session.cookies.map(c => `${c.name}=${c.value}`).join('; ');
const token = session.token;
const base = (session.portalUrl || 'https://integration.commonwellalliance.lkopera.com/').replace(/\/$/, '');
const url = base + '/TransactionLogs/BindTransactionLogs';

const windowMinutes = input.windowMinutes || 30;
const pageSize = input.pageSize || 100;
const portalTz = input.portalTimeZone || 'America/New_York';
const enc = encodeURIComponent;

function fmtInTz(d, tz) {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: tz, year:'numeric',month:'numeric',day:'numeric',hour:'numeric',minute:'2-digit',second:'2-digit',hour12:true }).formatToParts(d);
  const p = {}; for (const x of parts) p[x.type] = x.value;
  return `${p.month}/${p.day}/${p.year} ${p.hour}:${p.minute}:${p.second} ${p.dayPeriod}`;
}
const now = new Date();
const fromDate = fmtInTz(new Date(now.getTime() - windowMinutes*60000), portalTz);
const toDate = fmtInTz(now, portalTz);

function gridBody(page) {
  const fields = { sort:'transactionId-asc', page:String(page), pageSize:String(pageSize), group:'', filter:'', Status:'All', FromDate:fromDate, ToDate:toDate, organizationId:'', MemberId:'', TransactionType:'', TransactionId:'', before:'', after:'', __RequestVerificationToken:token };
  return Object.keys(fields).map(k => `${enc(k)}=${enc(fields[k])}`).join('&');
}

async function fetchPage(page) {
  const r = await this.helpers.httpRequest({
    method:'POST', url,
    headers:{ 'Cookie':cookie, 'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8', 'X-Requested-With':'XMLHttpRequest', 'Accept':'*/*', 'Origin':base, 'Referer':base+'/TransactionLogs/index' },
    body: gridBody(page), json:false
  });
  let resp = r;
  if (typeof resp === 'string') {
    const t = resp.trim();
    if (t.startsWith('<')) throw new Error('Got HTML instead of JSON — session expired. Re-run login.');
    resp = JSON.parse(t);
  }
  return resp;
}

let rows = [];
let page = 1;
const first = await fetchPage.call(this, page);
const total = (first && (first.Total||first.total)) || 0;
rows = rows.concat((first && (first.Data||first.data)) || []);
while (rows.length < total && page < 200) {
  page++;
  const nx = await fetchPage.call(this, page);
  const nr = (nx && (nx.Data||nx.data)) || [];
  if (!nr.length) break;
  rows = rows.concat(nr);
}

// --- group by transactionType (operation/method) ---
const isError = s => { const x=(s||'').toLowerCase(); return x && x!=='successful' && x!=='success'; };
const groups = {};
for (const r of rows) {
  const t = r.transactionType || 'Unknown';
  if (!groups[t]) groups[t] = { type:t, total:0, success:0, errors:0, statuses:{} };
  const g = groups[t];
  g.total++;
  if (isError(r.status)) g.errors++; else g.success++;
  const st = r.status || 'Unknown';
  g.statuses[st] = (g.statuses[st] || 0) + 1;
}

// sort groups by total desc
const groupList = Object.values(groups).sort((a,b) => b.total - a.total);
const totalErrors = groupList.reduce((s,g) => s + g.errors, 0);

return [{ json: { count: rows.length, total, totalErrors, fromDate, toDate, portalTz, webhookUrl: input.teamsWebhookUrl, groups: groupList } }];

// Build a Teams MessageCard listing transactions grouped by operation type,
// showing whatever status values CommonWell reports (no error interpretation).
const d = $input.first().json;

// one fact per operation type: "GetBinary_R4: 18 (ServerError: 15, Successful: 3)"
const groupFacts = (d.groups || []).map(g => {
  const statusBits = Object.keys(g.statuses).map(s => `${s}: ${g.statuses[s]}`).join(', ');
  return { name: g.type, value: `${g.total} — ${statusBits}` };
});

const title = `CommonWell: ${d.count} transaction(s) in ${d.groups.length} operation type(s)`;

const card = {
  '@type':'MessageCard', '@context':'http://schema.org/extensions',
  themeColor:'4A6FA5',
  summary: title,
  title: title,
  sections: [
    { facts: [ { name:'Window', value:`${d.fromDate} - ${d.toDate} (${d.portalTz})` }, { name:'Total', value:String(d.count) } ] },
    { activityTitle: '**By operation type**', facts: groupFacts }
  ]
};

return [{ json: { webhookUrl: d.webhookUrl, teamsCard: card } }];
